import argparse
import json
import logging
import socket
import socketserver
import threading
import time
from dataclasses import dataclass, asdict
from typing import Dict, List, Optional, Tuple

logging.basicConfig(level=logging.INFO, format="%(asctime)s %(levelname)s %(message)s")


@dataclass
class Player:
    name: str
    score: int = 0
    ping: int = 0
    team: str = "spectator"


@dataclass
class GameState:
    map_name: str = "default_map"
    game_mode: str = "deathmatch"
    max_players: int = 16
    current_players: int = 0
    match_time: int = 0
    round_number: int = 1
    server_name: str = "Python Game Server"
    passworded: bool = False
    dedicated: bool = True
    region: str = "global"
    version: str = "1.0.0"
    uptime: int = 0


class ServerState:
    def __init__(self):
        self.lock = threading.Lock()
        self.start_time = time.time()
        self.state = GameState()
        self.players: List[Player] = []
        self.recent_messages: List[str] = []
        self.extra: Dict[str, object] = {
            "motd": "Welcome to the server",
            "tags": ["python", "udp", "browser"],
            "rules": {
                "friendly_fire": False,
                "anti_cheat": True,
                "voice_chat": True,
            },
        }

    def snapshot(self) -> Dict[str, object]:
        with self.lock:
            now = int(time.time())
            self.state.current_players = len(self.players)
            self.state.uptime = now - int(self.start_time)
            self.state.match_time = now - int(self.start_time)
            return {
                "status": "ok",
                "state": asdict(self.state),
                "players": [asdict(p) for p in self.players],
                "recent_messages": list(self.recent_messages),
                "extra": self.extra,
                "timestamp": now,
            }

    def add_sample_players(self):
        with self.lock:
            if not self.players:
                self.players.extend(
                    [
                        Player(name="Alice", score=12, ping=34, team="red"),
                        Player(name="Bob", score=8, ping=56, team="blue"),
                        Player(name="Charlie", score=3, ping=78, team="red"),
                    ]
                )


class UDPRequestHandler(socketserver.BaseRequestHandler):
    def handle(self):
        data, sock = self.request
        client_ip, client_port = self.client_address
        try:
            message = data.decode("utf-8", errors="ignore").strip()
        except Exception:
            message = ""

        response = self.server.process_query(message, client_ip, client_port)
        if response is None:
            return

        payload = response.encode("utf-8")
        mtu = self.server.max_datagram_size
        if len(payload) <= mtu:
            sock.sendto(payload, self.client_address)
        else:
            total = (len(payload) + mtu - 1) // mtu
            query_id = int(time.time() * 1000) & 0xFFFFFFFF
            for index in range(total):
                chunk = payload[index * mtu : (index + 1) * mtu]
                header = f"PART {index+1}/{total} {query_id} ".encode("utf-8")
                sock.sendto(header + chunk, self.client_address)


class GameStatusUDPServer(socketserver.ThreadingMixIn, socketserver.UDPServer):
    allow_reuse_address = True
    daemon_threads = True

    def __init__(self, server_address, handler_class, state: ServerState, max_datagram_size: int = 1200):
        super().__init__(server_address, handler_class)
        self.state = state
        self.max_datagram_size = max_datagram_size

    def process_query(self, message: str, client_ip: str, client_port: int) -> Optional[str]:
        msg = message.upper()
        if not msg or msg in {"STATUS", "INFO", "PING", "SERVERINFO", "BROWSER"}:
            snap = self.state.snapshot()
            return json.dumps(snap, separators=(",", ":"), ensure_ascii=False)
        if msg.startswith("ECHO "):
            return message[5:]
        if msg.startswith("ADDPLAYER "):
            try:
                name = message[10:].strip() or f"Player_{client_port}"
                with self.state.lock:
                    self.state.players.append(Player(name=name))
                return json.dumps({"status": "added", "player": name})
            except Exception as e:
                return json.dumps({"status": "error", "error": str(e)})
        if msg == "HELP":
            return json.dumps(
                {
                    "commands": ["STATUS", "INFO", "PING", "SERVERINFO", "BROWSER", "ECHO <text>", "ADDPLAYER <name>", "HELP"],
                    "note": "Status queries are accepted from any IP address.",
                },
                separators=(",", ":"),
            )
        return json.dumps({"status": "error", "error": "unknown command"}, separators=(",", ":"))


def main():
    parser = argparse.ArgumentParser(description="UDP game status server")
    parser.add_argument("--host", default="0.0.0.0")
    parser.add_argument("--port", type=int, default=27015)
    parser.add_argument("--max-datagram-size", type=int, default=1200)
    args = parser.parse_args()

    state = ServerState()
    state.add_sample_players()

    server = GameStatusUDPServer((args.host, args.port), UDPRequestHandler, state, args.max_datagram_size)
    logging.info("UDP game status server listening on %s:%d", args.host, args.port)
    try:
        server.serve_forever()
    except KeyboardInterrupt:
        pass
    finally:
        server.server_close()


if __name__ == "__main__":
    main()